{
  "repository": "github.com/sg-evals/kafka--0753c489",
  "base_path": "streams/src/main/java/org/apache/kafka/streams",
  "summary": "Complete mapping of Kafka Streams DSL operations to their underlying Processor API implementations, organized by operation category. All paths are relative to streams/src/main/java/org/apache/kafka/streams/.",

  "processor_api_core_interfaces": {
    "description": "Public Processor API interfaces and base classes that custom implementations must extend/implement when migrating from DSL to Processor API.",
    "files": [
      {
        "path": "processor/api/Processor.java",
        "role": "Core interface for stateful or key-changing processors. Implement process(Record<KIn,VIn>) and optionally init()/close(). Used by DSL ops that change keys (map, flatMap, branch, joins).",
        "type_signature": "interface Processor<KIn, VIn, KOut, VOut>"
      },
      {
        "path": "processor/api/ProcessorSupplier.java",
        "role": "Factory interface returning a Processor instance. Implement get() and optionally stores() to declare state store dependencies. This is what you register with Topology.addProcessor().",
        "type_signature": "interface ProcessorSupplier<KIn, VIn, KOut, VOut> extends ConnectedStoreProvider"
      },
      {
        "path": "processor/api/FixedKeyProcessor.java",
        "role": "Variant of Processor for operations that never change the record key (mapValues, filter, peek). Safer than Processor when key stability is guaranteed.",
        "type_signature": "interface FixedKeyProcessor<KIn, VIn, VOut>"
      },
      {
        "path": "processor/api/FixedKeyProcessorSupplier.java",
        "role": "Factory interface returning a FixedKeyProcessor. Use with Topology.addProcessor() for key-preserving operations.",
        "type_signature": "interface FixedKeyProcessorSupplier<KIn, VIn, VOut> extends ConnectedStoreProvider"
      },
      {
        "path": "processor/api/ContextualProcessor.java",
        "role": "Abstract base class implementing Processor that stores the ProcessorContext. Extend this instead of implementing Processor directly to get context() convenience method.",
        "type_signature": "abstract class ContextualProcessor<KIn, VIn, KOut, VOut> implements Processor<KIn, VIn, KOut, VOut>"
      },
      {
        "path": "processor/api/ContextualFixedKeyProcessor.java",
        "role": "Abstract base class implementing FixedKeyProcessor that stores the FixedKeyProcessorContext. Extend this for key-preserving operations.",
        "type_signature": "abstract class ContextualFixedKeyProcessor<KIn, VIn, VOut> implements FixedKeyProcessor<KIn, VIn, VOut>"
      },
      {
        "path": "processor/api/ProcessorContext.java",
        "role": "Context available inside Processor.init(). Provides access to state stores (getStateStore()), record metadata, forwarding (forward()), scheduling (schedule()), and topic/partition info.",
        "type_signature": "interface ProcessorContext<KOut, VOut> extends ProcessingContext"
      },
      {
        "path": "processor/api/FixedKeyProcessorContext.java",
        "role": "Context available inside FixedKeyProcessor.init(). Same capabilities as ProcessorContext but typed for fixed-key processors.",
        "type_signature": "interface FixedKeyProcessorContext<KIn, VOut> extends ProcessingContext"
      },
      {
        "path": "processor/api/ProcessingContext.java",
        "role": "Base interface for both ProcessorContext and FixedKeyProcessorContext. Provides recordMetadata(), currentStreamTimeMs(), applicationId(), taskId(), appConfigs(), headers().",
        "type_signature": "interface ProcessingContext"
      },
      {
        "path": "processor/api/Record.java",
        "role": "Immutable record passed to Processor.process(). Contains key(), value(), timestamp(), headers(). Use withKey()/withValue()/withTimestamp() to create modified copies for forwarding.",
        "type_signature": "class Record<K, V>"
      },
      {
        "path": "processor/api/FixedKeyRecord.java",
        "role": "Immutable record passed to FixedKeyProcessor.process(). Same as Record but key() is guaranteed not to change; withValue()/withTimestamp() return FixedKeyRecord.",
        "type_signature": "class FixedKeyRecord<K, V>"
      },
      {
        "path": "processor/api/RecordMetadata.java",
        "role": "Metadata about the source record: topic(), partition(), offset(). Accessible via ProcessingContext.recordMetadata().",
        "type_signature": "class RecordMetadata"
      },
      {
        "path": "processor/api/ProcessorWrapper.java",
        "role": "Internal SPI for wrapping processors (used by instrumentation/testing hooks). Not needed for typical migrations.",
        "type_signature": "interface ProcessorWrapper"
      },
      {
        "path": "processor/api/WrappedProcessorSupplier.java",
        "role": "Internal SPI companion to ProcessorWrapper for wrapping ProcessorSupplier instances.",
        "type_signature": "interface WrappedProcessorSupplier<KIn, VIn, KOut, VOut>"
      },
      {
        "path": "processor/api/WrappedFixedKeyProcessorSupplier.java",
        "role": "Internal SPI companion to ProcessorWrapper for wrapping FixedKeyProcessorSupplier instances.",
        "type_signature": "interface WrappedFixedKeyProcessorSupplier<KIn, VIn, VOut>"
      }
    ]
  },

  "dsl_interfaces": {
    "description": "Public DSL interfaces that define the high-level streaming operations. These are what application code calls; each method delegates to an internal Processor API implementation.",
    "files": [
      {
        "path": "kstream/KStream.java",
        "role": "Primary DSL interface for record streams. Defines filter, filterNot, map, mapValues, flatMap, flatMapValues, groupBy, groupByKey, join, leftJoin, outerJoin, merge, peek, foreach, split, process, processValues, toTable.",
        "key_dsl_methods": ["filter", "filterNot", "map", "mapValues", "flatMap", "flatMapValues", "groupBy", "groupByKey", "join", "leftJoin", "outerJoin", "merge", "peek", "foreach", "split", "process", "processValues", "toTable"]
      },
      {
        "path": "kstream/KTable.java",
        "role": "DSL interface for changelog streams (key-value tables). Defines filter, filterNot, mapValues, groupBy, join, leftJoin, outerJoin, toStream, suppress, transformValues.",
        "key_dsl_methods": ["filter", "filterNot", "mapValues", "groupBy", "join", "leftJoin", "outerJoin", "toStream", "suppress", "transformValues"]
      },
      {
        "path": "kstream/KGroupedStream.java",
        "role": "DSL interface for a grouped KStream (result of KStream.groupBy/groupByKey). Defines aggregate, reduce, count, cogroup, windowedBy.",
        "key_dsl_methods": ["aggregate", "reduce", "count", "cogroup", "windowedBy"]
      },
      {
        "path": "kstream/KGroupedTable.java",
        "role": "DSL interface for a grouped KTable (result of KTable.groupBy). Defines aggregate, reduce, count.",
        "key_dsl_methods": ["aggregate", "reduce", "count"]
      },
      {
        "path": "kstream/TimeWindowedKStream.java",
        "role": "DSL interface for time-windowed grouped streams. Defines aggregate, reduce, count.",
        "key_dsl_methods": ["aggregate", "reduce", "count"]
      },
      {
        "path": "kstream/SessionWindowedKStream.java",
        "role": "DSL interface for session-windowed grouped streams. Defines aggregate, reduce, count.",
        "key_dsl_methods": ["aggregate", "reduce", "count"]
      },
      {
        "path": "kstream/CogroupedKStream.java",
        "role": "DSL interface for co-grouped streams (result of KGroupedStream.cogroup). Defines cogroup, aggregate, windowedBy.",
        "key_dsl_methods": ["cogroup", "aggregate", "windowedBy"]
      },
      {
        "path": "kstream/BranchedKStream.java",
        "role": "DSL interface for branched streams (result of KStream.split). Defines branch, defaultBranch, noDefaultBranch.",
        "key_dsl_methods": ["branch", "defaultBranch", "noDefaultBranch"]
      }
    ]
  },

  "dsl_implementations": {
    "description": "Internal DSL implementation classes. Each implements a DSL interface and wires together the Processor API backing classes into the topology graph.",
    "files": [
      {
        "path": "kstream/internals/KStreamImpl.java",
        "implements": "KStream<K, V>",
        "role": "Central DSL implementation. Each DSL method (filter, map, groupBy, etc.) creates the corresponding ProcessorSupplier, wraps it in ProcessorParameters, and adds a ProcessorGraphNode to the topology graph.",
        "key_methods_and_their_processor_suppliers": {
          "filter / filterNot": "KStreamFilter (FixedKeyProcessorSupplier)",
          "map": "KStreamMap (ProcessorSupplier)",
          "mapValues": "KStreamMapValues (FixedKeyProcessorSupplier)",
          "flatMap": "KStreamFlatMap (ProcessorSupplier)",
          "flatMapValues": "KStreamFlatMapValues (FixedKeyProcessorSupplier)",
          "foreach": "ForeachProcessor (Processor, via lambda supplier)",
          "peek": "KStreamPeek (FixedKeyProcessorSupplier)",
          "split / branch": "KStreamBranch (ProcessorSupplier)",
          "groupBy": "KStreamFilter (repartition) + KGroupedStreamImpl",
          "groupByKey": "KGroupedStreamImpl (no repartition if key unchanged)",
          "join (KStream-KStream)": "KStreamKStreamJoinLeftSide + KStreamKStreamJoinRightSide + KStreamJoinWindow",
          "leftJoin (KStream-KStream)": "KStreamKStreamJoinLeftSide + KStreamKStreamJoinRightSide + KStreamJoinWindow",
          "outerJoin (KStream-KStream)": "KStreamKStreamJoinLeftSide + KStreamKStreamJoinRightSide + KStreamJoinWindow",
          "join (KStream-KTable)": "KStreamKTableJoin (ProcessorSupplier)",
          "leftJoin (KStream-KTable)": "KStreamKTableJoin (ProcessorSupplier)",
          "leftJoin (KStream-GlobalKTable)": "KStreamGlobalKTableJoin (ProcessorSupplier)",
          "join (KStream-GlobalKTable)": "KStreamGlobalKTableJoin (ProcessorSupplier)",
          "process": "User-supplied ProcessorSupplier (direct Processor API escape hatch)",
          "processValues": "User-supplied FixedKeyProcessorSupplier (direct Processor API escape hatch)"
        }
      },
      {
        "path": "kstream/internals/KTableImpl.java",
        "implements": "KTable<K, S, V>",
        "role": "KTable DSL implementation. Wires KTableProcessorSupplier instances into the topology graph. Also manages change-log propagation (enableSendingOldValues).",
        "key_methods_and_their_processor_suppliers": {
          "filter / filterNot": "KTableFilter (KTableProcessorSupplier)",
          "mapValues": "KTableMapValues (KTableProcessorSupplier)",
          "transformValues": "KTableTransformValues (KTableProcessorSupplier)",
          "groupBy": "KTableRepartitionMap (KTableRepartitionMapSupplier)",
          "join (KTable-KTable inner)": "KTableKTableInnerJoin + KTableKTableJoinMerger",
          "leftJoin (KTable-KTable)": "KTableKTableLeftJoin + KTableKTableRightJoin + KTableKTableJoinMerger",
          "outerJoin (KTable-KTable)": "KTableKTableOuterJoin + KTableKTableJoinMerger",
          "toStream": "PassThrough (ProcessorSupplier)"
        }
      },
      {
        "path": "kstream/internals/KGroupedStreamImpl.java",
        "implements": "KGroupedStream<K, V>",
        "role": "Grouped stream DSL implementation. Delegates aggregate/reduce/count to GroupedStreamAggregateBuilder which creates KStreamAggregate or KStreamReduce processor suppliers.",
        "key_methods_and_their_processor_suppliers": {
          "aggregate": "KStreamAggregate (KStreamAggProcessorSupplier)",
          "reduce": "KStreamReduce (KStreamAggProcessorSupplier)",
          "count": "KStreamAggregate with LongAdder initializer",
          "windowedBy (TimeWindows)": "TimeWindowedKStreamImpl -> KStreamWindowAggregate",
          "windowedBy (SlidingWindows)": "TimeWindowedKStreamImpl -> KStreamSlidingWindowAggregate",
          "windowedBy (SessionWindows)": "SessionWindowedKStreamImpl -> KStreamSessionWindowAggregate",
          "cogroup": "CogroupedKStreamImpl -> CogroupedStreamAggregateBuilder"
        }
      },
      {
        "path": "kstream/internals/KGroupedTableImpl.java",
        "implements": "KGroupedTable<K, V>",
        "role": "Grouped table DSL implementation. Delegates to KTableAggregate and KTableReduce processor suppliers.",
        "key_methods_and_their_processor_suppliers": {
          "aggregate": "KTableAggregate (KTableProcessorSupplier)",
          "reduce": "KTableReduce (KTableProcessorSupplier)",
          "count": "KTableAggregate with LongAdder initializer"
        }
      },
      {
        "path": "kstream/internals/BranchedKStreamImpl.java",
        "implements": "BranchedKStream<K, V>",
        "role": "Branched stream DSL implementation. Each branch() call adds a KStreamFilter processor node downstream of the KStreamBranch split node."
      },
      {
        "path": "kstream/internals/CogroupedKStreamImpl.java",
        "implements": "CogroupedKStream<K, VOut>",
        "role": "Co-grouped stream DSL implementation. Delegates to CogroupedStreamAggregateBuilder which wires KStreamAggregate processors for each co-grouped stream."
      },
      {
        "path": "kstream/internals/TimeWindowedKStreamImpl.java",
        "implements": "TimeWindowedKStream<K, V>",
        "role": "Time-windowed stream DSL implementation. Creates KStreamWindowAggregate or KStreamSlidingWindowAggregate processor suppliers."
      },
      {
        "path": "kstream/internals/SessionWindowedKStreamImpl.java",
        "implements": "SessionWindowedKStream<K, V>",
        "role": "Session-windowed stream DSL implementation. Creates KStreamSessionWindowAggregate processor suppliers."
      },
      {
        "path": "kstream/internals/InternalStreamsBuilder.java",
        "implements": "InternalNameProvider",
        "role": "Internal topology builder. Translates the DSL graph (GraphNode tree) into InternalTopologyBuilder calls. Handles stream-table joins, repartitioning, and self-join optimization."
      },
      {
        "path": "kstream/internals/KStreamImplJoin.java",
        "role": "Helper class for KStream-KStream join wiring. Creates KStreamJoinWindow (for buffering), KStreamKStreamJoinLeftSide, and KStreamKStreamJoinRightSide processor suppliers and connects them in the topology."
      },
      {
