  "migration_guide": {
    "description": "Step-by-step guidance for migrating from DSL to Processor API for custom state store management.",

    "key_concepts": [
      {
        "concept": "State Store Declaration",
        "dsl_approach": "Pass Materialized.as(storeName) to DSL methods like aggregate(), reduce(), filter().",
        "processor_api_approach": "Create a StoreBuilder (e.g., Stores.timestampedKeyValueStoreBuilder()) and register it via Topology.addStateStore(storeBuilder, processorName). Declare it in ProcessorSupplier.stores() so it is automatically connected.",
        "example": "StoreBuilder<TimestampedKeyValueStore<K,V>> storeBuilder = Stores.timestampedKeyValueStoreBuilder(Stores.persistentTimestampedKeyValueStore(storeName), keySerde, valueSerde); topology.addStateStore(storeBuilder, 'my-processor');"
      },
      {
        "concept": "Accessing State Stores",
        "dsl_approach": "Implicit — the DSL wires stores automatically.",
        "processor_api_approach": "In Processor.init(ProcessorContext context), call context.getStateStore(storeName) to get a typed reference. Store it as a field for use in process().",
        "example": "public void init(ProcessorContext<KOut,VOut> context) { this.store = context.getStateStore('my-store'); }"
      },
      {
        "concept": "Forwarding Records",
        "dsl_approach": "Implicit — DSL chains handle forwarding.",
        "processor_api_approach": "Call context.forward(record) or context.forward(record, childName) inside process(). For FixedKeyProcessor, call context.forward(record.withValue(newValue)).",
        "example": "context.forward(record.withKey(newKey).withValue(newValue));"
      },
      {
        "concept": "Punctuation / Scheduling",
        "dsl_approach": "Not directly exposed in DSL (except suppress()).",
        "processor_api_approach": "In init(), call context.schedule(Duration, PunctuationType, timestamp -> { ... }) to register a Punctuator for periodic actions (e.g., emitting windowed results on wall-clock time).",
        "example": "context.schedule(Duration.ofSeconds(1), PunctuationType.WALL_CLOCK_TIME, ts -> { /* emit */ });"
      },
      {
        "concept": "KTable Change Semantics",
        "dsl_approach": "Handled transparently by DSL.",
        "processor_api_approach": "KTable processors receive Change<V> records (oldValue + newValue). When implementing KTable-equivalent logic, always handle both the retraction (oldValue) and assertion (newValue) to maintain correct aggregate state.",
        "example": "Change<V> change = record.value(); V oldVal = change.oldValue; V newVal = change.newValue;"
      },
      {
        "concept": "Repartitioning for groupBy",
        "dsl_approach": "KStream.groupBy() automatically inserts a repartition topic.",
        "processor_api_approach": "Use Topology.addSink() to write to a repartition topic and Topology.addSource() to read from it, then add your aggregate processor downstream. Alternatively, use the DSL's groupBy() and only replace the aggregate step with a custom processor via KGroupedStream.aggregate() with a custom Aggregator.",
        "example": "topology.addSink('repartition-sink', 'repartition-topic', ..., 'upstream-processor'); topology.addSource('repartition-source', 'repartition-topic'); topology.addProcessor('aggregate-processor', myAggSupplier, 'repartition-source');"
      }
    ],

    "dsl_to_processor_api_method_map": {
      "KStream.filter(predicate)": {
        "processor_api_class": "FixedKeyProcessor<K,V,V>",
        "backing_file": "kstream/internals/KStreamFilter.java",
        "pattern": "In process(): if (predicate.test(record.key(), record.value())) context.forward(record);"
      },
      "KStream.map(mapper)": {
        "processor_api_class": "Processor<KIn,VIn,KOut,VOut>",
        "backing_file": "kstream/internals/KStreamMap.java",
        "pattern": "In process(): KeyValue<KOut,VOut> kv = mapper.apply(record.key(), record.value()); context.forward(record.withKey(kv.key).withValue(kv.value));"
      },
      "KStream.mapValues(mapper)": {
        "processor_api_class": "FixedKeyProcessor<K,VIn,VOut>",
        "backing_file": "kstream/internals/KStreamMapValues.java",
        "pattern": "In process(): VOut newVal = mapper.apply(record.key(), record.value()); context.forward(record.withValue(newVal));"
      },
      "KStream.flatMap(mapper)": {
        "processor_api_class": "Processor<KIn,VIn,KOut,VOut>",
        "backing_file": "kstream/internals/KStreamFlatMap.java",
        "pattern": "In process(): for (KeyValue<KOut,VOut> kv : mapper.apply(record.key(), record.value())) context.forward(record.withKey(kv.key).withValue(kv.value));"
      },
      "KStream.flatMapValues(mapper)": {
        "processor_api_class": "FixedKeyProcessor<K,VIn,VOut>",
        "backing_file": "kstream/internals/KStreamFlatMapValues.java",
        "pattern": "In process(): for (VOut v : mapper.apply(record.key(), record.value())) context.forward(record.withValue(v));"
      },
      "KStream.groupBy(selector).aggregate(init, agg, materialized)": {
        "processor_api_class": "Processor<K,V,K,Change<VAgg>> with TimestampedKeyValueStore",
        "backing_file": "kstream/internals/KStreamAggregate.java",
        "pattern": "In process(): VAgg current = store.get(record.key()); VAgg updated = aggregator.apply(record.key(), record.value(), current == null ? initializer.apply() : current.value()); store.put(record.key(), ValueAndTimestamp.make(updated, record.timestamp())); context.forward(record.withValue(new Change<>(updated, current)));"
      },
