        "processor_api_class": "Processor<K,V,K,Change<V>> with TimestampedKeyValueStore",
        "backing_file": "kstream/internals/KStreamReduce.java",
        "pattern": "Same as aggregate but apply reducer.apply(currentValue, newValue) instead of aggregator."
      },
