        "processor_api_class": "Processor<K,V,Windowed<K>,Change<VAgg>> with TimestampedWindowStore",
        "backing_file": "kstream/internals/KStreamWindowAggregate.java",
        "pattern": "In process(): determine window boundaries, fetch current aggregate from TimestampedWindowStore, apply aggregator, put back, forward Windowed<K> + Change<VAgg>. Schedule punctuator to emit/close windows."
      },
      "KTable.filter(predicate)": {
        "processor_api_class": "Processor<K,Change<V>,K,Change<V>> with optional KeyValueStore",
        "backing_file": "kstream/internals/KTableFilter.java",
        "pattern": "In process(): Change<V> change = record.value(); V newVal = predicate.test(record.key(), change.newValue) ? change.newValue : null; V oldVal = predicate.test(record.key(), change.oldValue) ? change.oldValue : null; if (newVal != oldVal) context.forward(record.withValue(new Change<>(newVal, oldVal)));"
      },
      "KTable.mapValues(mapper)": {
        "processor_api_class": "Processor<K,Change<V>,K,Change<VOut>> with optional KeyValueStore",
        "backing_file": "kstream/internals/KTableMapValues.java",
        "pattern": "In process(): Change<V> change = record.value(); VOut newMapped = change.newValue != null ? mapper.apply(record.key(), change.newValue) : null; VOut oldMapped = change.oldValue != null ? mapper.apply(record.key(), change.oldValue) : null; context.forward(record.withValue(new Change<>(newMapped, oldMapped)));"
      },
      "KTable.groupBy(selector).aggregate(adder, subtractor, materialized)": {
        "processor_api_class": "Processor<K,Change<V>,K,Change<VAgg>> with TimestampedKeyValueStore",
        "backing_file": "kstream/internals/KTableAggregate.java",
        "pattern": "In process(): subtract old value using subtractor aggregator, add new value using adder aggregator, update store, forward Change<VAgg>."
      }
    }
